mapper.select:
SELECT id, occurred_at AS occurredAt, actor_username AS actor, action, target_user_id AS targetUserId, target_username AS targetUsername, field_name AS fieldName, old_value AS oldValue, new_value AS newValue, project, note FROM rf_user_audit_log
AND actor_username = #{actor}
AND action = #{action}
ORDER BY occurred_at DESC, id DESC LIMIT #{limit}
